#nullable enable // autogenerated

using MukioI18n;
using MVZ2.GameContent.Effects;
using MVZ2.Vanilla.Audios;
using MVZ2.Vanilla.Definitions;
using MVZ2.Vanilla.Entities;
using MVZ2.Vanilla.Localization;
using MVZ2.Vanilla.RandomChina;
using MVZ2Logic.Entities;
using MVZ2Logic.Level;
using PVZEngine.Entities;
using Tools;

namespace MVZ2.GameContent.RandomChinaEvents
{
    [RandomChinaEventDefinition(VanillaRandomChinaEventNames.theEmpress)]
    public class TheEmpressEvent : RandomChinaEventDefinition
    {
        public TheEmpressEvent(string nsp, string path) : base(nsp, path, NAME, DESCRIPTION)
        {
        }
        public override void Run(Entity contraption, RandomGenerator rng)
        {
            var pos = contraption.Position;
            pos.z -= 8f;
            pos.y = contraption.Level.GetGroundY(pos.x, pos.z);
            var param = contraption.GetSpawnParams();
            param.SetProperty(Miner.PROP_WORKS_ALL_DAY, true);
            contraption.Spawn(VanillaEffectID.miner, pos, param)?.Let(m =>
            {
                m.Timeout = 5400;
            });
            contraption.PlaySound(VanillaSoundID.teslaConstruction);
        }
        [TranslateMsg("随机瓷器事件名称", VanillaStrings.CONTEXT_RANDOM_CHINA_EVENT_NAME)]
        public const string NAME = "III-女皇";
        [TranslateMsg("随机瓷器事件描述", VanillaStrings.CONTEXT_RANDOM_CHINA_EVENT_DESCRIPTION)]
        public const string DESCRIPTION = "生成一个全天工作的矿场，持续3分钟";
    }
}
